ValidationRule.errorConditionFormula:
AND( NOT($Setup.RES_Config_Switch__c.RES_Validation_Rules_Off__c),
OR( $RecordType.DeveloperName = "RES_Company", $RecordType.DeveloperName = "RES_Individual" ),
OR( /* Existing Specialist Roles */ $UserRole.DeveloperName = "RES_Contract_Amendments_Operations_Specialist", $UserRole.DeveloperName = "RES_External_Sales_Operations_Operations_Specialist", $UserRole.DeveloperName = "RES_Internal_Sales_Operations_Operations_Specialist", $UserRole.DeveloperName = "RES_Operational_Excellence_Operations_Specialist", $UserRole.DeveloperName = "RES_Sales_DI_Specialist", $UserRole.DeveloperName = "RES_Sales_DII_Specialist", $UserRole.DeveloperName = "RES_Sales_External_Specialist", $UserRole.DeveloperName = "RES_Sales_Implementation_Excellence_Specialist", $UserRole.DeveloperName = "RES_Sales_Planning_Specialist", $UserRole.DeveloperName = "RES_Sales_Wadi_Safar_Specialist_I", $UserRole.DeveloperName = "RES_Sales_Wadi_Safar_Specialist_II",
/* Senior Director / Director Roles */ $UserRole.DeveloperName = "RES_Sales_DI_DII_Senior_Director", $UserRole.DeveloperName = "RES_Sales_Excellence_Associate_Director", $UserRole.DeveloperName = "RES_Sales_Excellence_Senior_Director", $UserRole.DeveloperName = "RES_Sales_External_Senior_Director", $UserRole.DeveloperName = "RES_Sales_Operations_Executive_Director", $UserRole.DeveloperName = "RES_Sales_Wadi_Safar_Senior_Director", $UserRole.DeveloperName = "RES_Treasury_Executive_Director",
/* Operations / Manager Roles */ $UserRole.DeveloperName = "RES_External_Sales_Operations_Operations_Senior_Manager", $UserRole.DeveloperName = "RES_Internal_Sales_Contracts_Operations_Senior_Manager", $UserRole.DeveloperName = "RES_Internal_Sales_Operations_Operations_Manager", $UserRole.DeveloperName = "RES_Operational_Excellence_Operations_Manager",
/* Sales Manager Roles */ $UserRole.DeveloperName = "RES_Sales_Compliance_Manager", $UserRole.DeveloperName = "RES_Sales_DII_Manager", $UserRole.DeveloperName = "RES_Sales_DI_Manager", $UserRole.DeveloperName = "RES_Sales_DI_Relationship_Manager", $UserRole.DeveloperName = "RES_Sales_DI_Senior_Manager", $UserRole.DeveloperName = "RES_Sales_External_Manager", $UserRole.DeveloperName = "RES_Sales_External_Relationship_Manager", $UserRole.DeveloperName = "RES_Sales_Planning_Senior_Manager", $UserRole.DeveloperName = "RES_Sales_Wadi_Safar_Manager", $UserRole.DeveloperName = "RES_Sales_Wadi_Safar_Senior_Manager" ),
ISCHANGED(OwnerId) )
